scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch, row) {
  if (row == null || row == "") {
    row = 0;
  }
  let deptCd = lc_deptCd.getValue();
  let postSeq = lc_postSeq.getValue();
  switch (disGubun) {
    case 1:
      udc_postSeqEmpNo.cfCommonPopUp(scwin.udc_postSeqEmpNo_callBackFunc, pCode, pName, pClose, null, "신청자코드, 신청자명", "100,200", '3,4,5,6,7,8,9,10', deptCd, null, null, null, null, null, "T", "신청자코드,신청자코드,신청자명");
      break;
    case 2:
      udc_gr_postSeqEmpNo.cfCommonPopUp(scwin.udc_gr_postSeqEmpNo_callBackFunc, pCode, pName, pClose, null, "신청자코드, 신청자명", "100,200", '3,4,5,6,7,8,9,10', deptCd, null, null, null, null, null, "T", "신청자코드,신청자코드,신청자명");
      break;
    default:
      break;
  }
};
scwin.gr_out_ontextimageclick = function (rowIndex, colId, nowValue) {
  if (colId == "name") {
    scwin.f_openCommonPopUp(2, '', nowValue, 'F', 'T', rowIndex);
  }
};
scwin.udc_postSeqEmpNo_callBackFunc = function (rtnList) {
  if (rtnList != null && rtnList[0] != "N/A") {
    ed_empNo.setValue(rtnList[0]);
    ed_empNm.setValue(rtnList[1]);
  } else {
    //ed_empNo.setValue("999999");
    ed_empNo.setValue("");
    ed_empNm.setValue(ed_empNm.getValue());
  }
};
