//-------------------------------------------------------------------------
// 전표 등록자 조회
//-------------------------------------------------------------------------
// 전년도복사를 위한 데이터
scwin.getPreviousYearData = function (postSeq, acctDeptCd) {
  let post = postSeq.substring(0, 4) - 1;
  ds_checkPreviousYearData.removeAll();

  // SELECT 절 
  let param1 = " A.POST_SEQ   as COL1 " + ",A.DEPT_CD    as COL2 " + ",''   		as COL3 " + ",''   		as COL4 " + ",''  		as COL5 " + ",'' 			as COL6 " + ",'' 			as COL7 " + ",'' 			as COL8 " + ",'' 			as COL9 " + ",'' 			as COL10 ";

  // 대상테이블 	
  let param2 = " TB_ZZ783 A, TB_ZZ002 B, TB_ZZ002 C " + " WHERE 1=1 " + " AND A.POST_SEQ  BETWEEN '" + post + "' || '01' AND '" + post + "' || '12'" + " AND B.GRP_CD = 'DRESS' " + " AND C.GRP_CD = 'DRS_L' " + " AND B.UPPER_CD = C.CD " + " AND A.DEPT_CD = B.CD " + " AND C.CD = '" + acctDeptCd + "'" + " AND A.ITEM_NO IN ( " + " 		         SELECT ITEM_NO " + "              	   FROM TB_ZZ782 " + "             	   WHERE POST_SEQ = '" + postSeq + "' ) " + " ORDER BY A.POST_SEQ ";

  //let condition = "&param1=" + param1 + "&param2=" + param2;

  const strParam = {
    sysCd: "CommonEBC",
    queryId: "dinymicQueryTest2",
    param1: param1,
    param2: param2
  };
  ds_check_param.setJSON(strParam);
  $c.sbm.execute($p, sbm_ds_checkPreviousYearData);
};

//-------------------------------------------------------------------------
// 전표 등록자 조회
//-------------------------------------------------------------------------
scwin.getfirstProvideCd = function (postSeq, sabun) {
  let post1 = postSeq.substring(0, 4) - 1;
  ds_firstProvideCd.removeAll();

  // SELECT 절 
  let param1 = " 	CASE " + " 		WHEN EXISTS ( " + " 						SELECT * " + " 						  FROM TB_ZZ783 K " + " 						 WHERE A.EMP_NO = K.SABUN " + " 						   AND K.POST_SEQ  BETWEEN '" + post1 + "' || '01' AND '" + post1 + "' || '12'" + " 						   AND K.ITEM_NO IN ( " + " 											SELECT ITEM_NO " + " 											  FROM TB_ZZ782 " + " 											 WHERE POST_SEQ = '" + postSeq + "' )) THEN '1' " + " 		WHEN A.MCOM_ENT_DT <= TO_CHAR(ADD_MONTHS(SYSDATE, -12), 'YYYYMMDD') THEN '2' " + " 	ELSE '3' " + " END AS COL1 " + ",''    		as COL2 " + ",''   		as COL3 " + ",''   		as COL4 " + ",''  		as COL5 " + ",'' 			as COL6 " + ",'' 			as COL7 " + ",'' 			as COL8 " + ",'' 			as COL9 " + ",'' 			as COL10 ";

  // 대상테이블 	
  let param2 = " TB_ZZ310 A ";

  // 조건절	  
  let param3 = " AND A.EMP_NO = '" + sabun + "'  ";

  // 정렬    
  let param4 = " COL1 ";
  let condition = "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
  const strParam = {
    sysCd: "CommonEBC",
    queryId: "dinymicQueryTest",
    param1: param1,
    param2: param2,
    param3: param3,
    param4: param4
  };
  ds_check_first_param.setJSON(strParam);
  $c.sbm.execute($p, sbm_ds_firstProvideCd);
};

